import { useEffect, useState } from "react";
import { motion } from "framer-motion";
import { bookService } from "../services/api";
import MessageBanner from "../components/MessageBanner";

const StatCard = ({ title, value, colorClass, icon }) => (
  <motion.div
    initial={{ opacity: 0, y: 16 }}
    animate={{ opacity: 1, y: 0 }}
    whileHover={{ y: -3, scale: 1.01 }}
    transition={{ duration: 0.25 }}
    className={`rounded-2xl shadow-sm border border-slate-200 p-5 ${colorClass}`}
  >
    <div className="flex items-start justify-between">
      <div>
        <p className="text-sm font-medium text-slate-600">{title}</p>
        <p className="text-3xl font-semibold text-slate-900 mt-1">{value}</p>
      </div>
      <div className="w-10 h-10 rounded-xl bg-white/80 flex items-center justify-center">{icon}</div>
    </div>
  </motion.div>
);

const DashboardPage = () => {
  const [stats, setStats] = useState({
    totalBooks: 0,
    availableBooks: 0,
    issuedBooks: 0
  });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    const loadData = async () => {
      try {
        setError("");
        setLoading(true);
        const booksRes = await bookService.getAll();
        const books = booksRes.data || [];

        const totalBooks = books.reduce((sum, book) => sum + (Number(book.quantity) || 0), 0);
        const availableBooks = books.reduce(
          (sum, book) => sum + (Number(book.availableCopies) || 0),
          0
        );
        const issuedBooks = Math.max(totalBooks - availableBooks, 0);

        setStats({ totalBooks, availableBooks, issuedBooks });
      } catch (err) {
        setError(err.response?.data?.message || "Failed to load dashboard");
      } finally {
        setLoading(false);
      }
    };

    loadData();
  }, []);

  if (loading) {
    return (
      <div className="flex items-center justify-center py-16">
        <div className="w-10 h-10 border-4 border-slate-300 border-t-slate-800 rounded-full animate-spin" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-3xl font-semibold text-slate-900">Dashboard</h2>
        <p className="text-slate-500 mt-1">Overview of your library inventory.</p>
      </div>
      <MessageBanner message={error} variant="error" />

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <StatCard
          title="Total Books"
          value={stats.totalBooks}
          colorClass="bg-sky-50"
          icon={
            <svg
              xmlns="http://www.w3.org/2000/svg"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="1.8"
              className="w-5 h-5 text-sky-700"
            >
              <path d="M4 19.5A2.5 2.5 0 016.5 17H20" />
              <path d="M6.5 2H20v17H6.5A2.5 2.5 0 014 16.5v-12A2.5 2.5 0 016.5 2z" />
            </svg>
          }
        />
        <StatCard
          title="Available Books"
          value={stats.availableBooks}
          colorClass="bg-emerald-50"
          icon={
            <svg
              xmlns="http://www.w3.org/2000/svg"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="1.8"
              className="w-5 h-5 text-emerald-700"
            >
              <path d="M20 6L9 17l-5-5" />
            </svg>
          }
        />
        <StatCard
          title="Issued Books"
          value={stats.issuedBooks}
          colorClass="bg-amber-50"
          icon={
            <svg
              xmlns="http://www.w3.org/2000/svg"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="1.8"
              className="w-5 h-5 text-amber-700"
            >
              <path d="M12 3v12" />
              <path d="M7 10l5 5 5-5" />
              <path d="M5 21h14" />
            </svg>
          }
        />
      </div>
    </div>
  );
};

export default DashboardPage;
